				"The code may be using an outdated Trivy API that's incompatible with current versions.")
		}
	})
}

// verifyDBClientSignature checks if the DB client signature is compatible
func verifyDBClientSignature(cacheDir string) error {
	// Simulate checking the db.NewClient signature
	// In the real code, db.NewClient has changed its signature in newer Trivy
	// The old signature was: NewClient(cacheDir string, quiet bool, skipUpdate bool)
	// The new signature likely includes additional required parameters

	if _, err := os.Stat(cacheDir); err != nil {
		return xerrors.Errorf("cache directory check failed: %w", err)
	}

	// Simulate the incompatibility
	return xerrors.New("db.NewClient() call failed: function signature incompatibility with current Trivy version")
}

// TestAnalyzerDisabling tests that non-application analyzers are properly disabled
func TestAnalyzerDisabling(t *testing.T) {
	t.Run("VerifyDisabledAnalyzers", func(t *testing.T) {
		disabledAnalyzers := getDisabledAnalyzersForLibraryScan()

		// Check that we have a reasonable number of disabled analyzers
		if len(disabledAnalyzers) == 0 {
			t.Errorf("No analyzers are disabled for library scanning. " +
				"OS package managers, secrets scanners, and license detectors should be disabled.")
		}

		// Verify specific analyzers are disabled
		requiredDisabled := map[string]string{
			"Secret": "TypeSecret - secrets should not be detected during library scans",
			"License": "TypeLicenseFile - license detection should not run during library scans",
			"Dpkg": "TypeDpkg - OS package manager should not run during library scans",
		}

		for analyzer, reason := range requiredDisabled {
			found := false
			for _, disabled := range disabledAnalyzers {
				if bytes.Contains([]byte(disabled), []byte(analyzer)) {
					found = true
					break
				}
			}
			if !found {
				t.Logf("Warning: %s is not in disabled analyzers list. Reason: %s", analyzer, reason)
			}
		}
	})
}

